import './style.css';
import { cva, type VariantProps } from 'class-variance-authority';
import { Slot } from 'radix-ui';

import { cn } from '@/lib/utils';

/*
 * @author: @joao-carmassi
 * @description: Enhanced badge component with multiple variants, sizes, and visual effects
 * @version: 1.0.0
 * @date: 2026-08-03
 * @license: MIT
 * @website: https://joao-carmassi.github.io/enhanced-button-v4/
 * @github: https://github.com/joao-carmassi/enhanced-button-v4
 */

const badgeVariants = cva(
  'group/badge inline-flex w-fit shrink-0 items-center justify-center gap-1 overflow-hidden rounded-4xl border border-transparent font-medium whitespace-nowrap transition-all focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 has-data-[icon=inline-end]:pr-1.5 has-data-[icon=inline-start]:pl-1.5 aria-invalid:border-destructive aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 [&>svg]:pointer-events-none',
  {
    variants: {
      variant: {
        default: 'bg-primary text-primary-foreground [a]:hover:bg-primary/80',
        secondary:
          'bg-secondary text-secondary-foreground [a]:hover:bg-secondary/80',
        destructive:
          'bg-destructive/10 text-destructive focus-visible:ring-destructive/20 dark:bg-destructive/20 dark:focus-visible:ring-destructive/40 [a]:hover:bg-destructive/20',
        outline:
          'border-border text-foreground [a]:hover:bg-muted [a]:hover:text-muted-foreground',
        ghost:
          'hover:bg-muted hover:text-muted-foreground dark:hover:bg-muted/50',
        link: 'text-primary underline-offset-4 [a&]:hover:underline',
      },
      effect: {
        shine:
          'before:animate-shine-effect relative overflow-hidden before:absolute before:inset-0 before:rounded-[inherit] before:bg-[linear-gradient(45deg,transparent_25%,rgba(255,255,255,0.5)_50%,transparent_75%,transparent_100%)] before:bg-[length:250%_250%,100%_100%] before:bg-no-repeat',
        pulsating: 'animate-pulsating-effect',
        rainbow:
          'relative animate-rainbow-effect hover:brightness-110 border-0 bg-[linear-gradient(#121213,#121213),linear-gradient(#121213_50%,rgba(18,18,19,0.6)_80%,rgba(18,18,19,0)),linear-gradient(90deg,oklch(66.2%_0.225_25.9)_0%,oklch(90.7%_0.231_133)_20%,oklch(69.6%_0.165_251)_40%,oklch(80.2%_0.134_225)_60%,oklch(60.4%_0.26_302)_80%,oklch(66.2%_0.225_25.9)_100%)] bg-[length:200%] text-primary-foreground [background-clip:padding-box,border-box,border-box] [background-origin:border-box] [border:calc(0.125rem)_solid_transparent] before:absolute before:bottom-[-20%] before:left-1/2 before:z-0 before:h-1/5 before:w-3/5 before:-translate-x-1/2 before:animate-rainbow before:bg-[linear-gradient(90deg,oklch(66.2%_0.225_25.9)_0%,oklch(90.7%_0.231_133)_20%,oklch(69.6%_0.165_251)_40%,oklch(80.2%_0.134_225)_60%,oklch(60.4%_0.26_302)_80%,oklch(66.2%_0.225_25.9)_100%)] before:[filter:blur(0.75rem)] dark:bg-[linear-gradient(#fff,#fff),linear-gradient(#fff_50%,rgba(255,255,255,0.6)_80%,rgba(0,0,0,0)),linear-gradient(90deg,oklch(66.2%_0.225_25.9)_0%,oklch(90.7%_0.231_133)_20%,oklch(69.6%_0.165_251)_40%,oklch(80.2%_0.134_225)_60%,oklch(60.4%_0.26_302)_80%,oklch(66.2%_0.225_25.9)_100%)]',
      },
      size: {
        default: 'h-5 px-2 py-0.5 text-xs [&_svg]:size-3',
        lg: 'h-6 px-3 py-1 text-sm [&_svg]:size-4',
        icon: 'size-5 [&_svg]:size-3',
        'icon-lg': 'size-7 [&_svg]:size-4',
      },
    },
    defaultVariants: {
      variant: 'default',
      size: 'default',
    },
  },
);

function Badge({
  className,
  variant = 'default',
  size = 'default',
  effect,
  asChild = false,
  ...props
}: React.ComponentProps<'span'> &
  VariantProps<typeof badgeVariants> & { asChild?: boolean }) {
  const Comp = asChild ? Slot.Root : 'span';

  return (
    <Comp
      data-slot='badge'
      data-variant={variant}
      data-size={size}
      className={cn(badgeVariants({ variant, size, effect }), className)}
      {...props}
    />
  );
}

export { Badge, badgeVariants };

[data-variant='default'] {
  --pulse-color: var(--primary);
}
[data-variant='destructive'] {
  --pulse-color: var(--destructive);
}
[data-variant='secondary'] {
  --pulse-color: var(--secondary-foreground);
}
[data-variant='outline'] {
  --pulse-color: var(--ring);
}
[data-variant='ghost'] {
  --pulse-color: var(--ring);
}

.before\:animate-shine-effect::before {
  animation: shine-effect 3s ease-out infinite;
}

.animate-rainbow-effect {
  animation: rainbow-effect 3s linear infinite;
}

.animate-pulsating-effect {
  animation: pulsating-effect 1.5s ease-out infinite;
}

.card-shine-effect {
  animation: card-shine-effect var(--duration) infinite linear;
}

@keyframes shine-effect {
  0% {
    background-position: 200% 0;
  }
  25% {
    background-position: -200% 0;
  }
  100% {
    background-position: -200% 0;
  }
}

@keyframes rainbow-effect {
  0% {
    background-position: 0%;
  }
  100% {
    background-position: 200%;
  }
}

@keyframes pulsating-effect {
  0% {
    box-shadow: 0 0 0 0 var(--pulse-color, currentColor);
  }
  70% {
    box-shadow: 0 0 0 8px transparent;
  }
  100% {
    box-shadow: 0 0 0 0 transparent;
  }
}

@keyframes card-shine-effect {
  0% {
    background-position: 0% 0%;
  }
  50% {
    background-position: 100% 100%;
  }
  to {
    background-position: 0% 0%;
  }
}
